var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>3년전, 북방합의체의 어느 연구소</color>","JPN":"<color=#ffd34c>3年前、北方合意体のとある研究所</color>","ENG":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>","TWN":"<color=#ffd34c>3年前， 北方和議會某研究所</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"사샤의 상태는?","JPN":"サシャの状態は？","ENG":"How's Sasha doing?","TWN":"莎夏的情況如何？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"카운터 능력이 발현되었지만, 거의 사용하려 하지 않네요.","JPN":"カウンター能力が発現しましたが、まったく使おうとしません。","ENG":"Her Counter ability has been activated, but she hardly uses it.","TWN":"雖然制裁者能力已經顯現，但幾乎不怎麼使用。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"발현하다 만 케이스도 많으니까, 좀 더 지켜봐야겠지.","JPN":"発現の途中で中断されるケースも多いから、もう少し見守るべきだろう。","ENG":"There are many cases where Counter abilities don't fully manifest, so we'll have to wait and see.","TWN":"有很多個顯現部分能力的案例，還需要再觀察。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그림자로 변이되면 어떻게 다룰 수 있을지도 생각해 봐야겠습니다.","JPN":"シャドウに変異したら、どう対処するかも考えておかないとですね。","ENG":"For now, we should think about how to handle her if she turns into a Shadow.","TWN":"如果變成暗影，還得考慮怎麼處理。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"마음 아프게 됐군.","JPN":"心が痛むな。","ENG":"That's heartbreaking.","TWN":"那真是令人心痛。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그런 말도 할 줄 아시네요 박사님.","JPN":"博士はそんな言葉も知っているんですね。","ENG":"So you do know how to say things like that, Doctor.","TWN":"博士也會說這種話嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"……특이증상에 대해서 다시 말해주게.","JPN":"……特異症状についてもう一度聞かせてくれ。","ENG":"...Tell me again about her specific symptoms.","TWN":"……再說一遍關於特殊症狀的事。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"현재까지 발견된 증상으로는 총 2가지입니다.","JPN":"今まで発見された症状としては、2つあります。","ENG":"Currently, there are two symptoms discovered.","TWN":"目前發現的症狀總共有兩種。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>불규칙적으로 일어나는 고열.</color>","JPN":"<color=#ffd34c>不規則に発生する高熱。</color>","ENG":"The <color=#ffd34c>irregular occurrence of fever breaks,</color>","TWN":"<color=#ffd34c>不規律的高燒</color>。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그리고 <color=#ffd34c>기면증</color> 정도가 있습니다.","JPN":"そして<color=#ffd34c>嗜眠</color>です。","ENG":"and the other is <color=#ffd34c>narcolepsy</color>.","TWN":"還有<color=#ffd34c>嗜睡症</color>。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"잠이란 건 죽음에 대비해 미리 연습하는 거라는 말이 있었잖아요?","JPN":"眠りとは、死に備えての予行練習だというじゃないですか。","ENG":"You know how people say that sleeping is just preparing for death?","TWN":"不是有句話說，睡眠是為了預先練習死亡嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그렇게 생각하니 조금 마음이 묘해지네요.","JPN":"そう思うと、少し妙な気持ちになりますね。","ENG":"Thinking about it like that makes me feel a little strange.","TWN":"這麼一想，心情有點複雜呢。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"죽음이라….","JPN":"死か……","ENG":"Death...","TWN":"死亡啊……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"비상입니다! 사샤가 도주한 것 같습니다!","JPN":"非常事態です！　サシャが逃走したようです！","ENG":"Critical alert! Sasha has run away!","TWN":"緊急情況！莎夏好像逃跑了！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"어떻게…?! 지금 카메라에도 얌전히 앉아 있는거로 보이는데요?","JPN":"どうやって……！？　今、カメラには大人しく座ってるように見えますけど？","ENG":"How...?! The camera shows her sitting quietly!","TWN":"怎麼可能……？！現在鏡頭裡還看到她乖乖坐著呢？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"능력으로 조작한 것 같습니다! 카메라에 비친 건 가짜라고요!","JPN":"能力で捏造したみたいです！　カメラに映っているのは偽物ですよ！","ENG":"I think she manipulated it with her ability! What's shown on camera is a fake!","TWN":"好像是用能力操控的！鏡頭裡的是假的！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"박사님, 병사들을 전부 풀어 수색해야 합니다!","JPN":"博士、全兵士を動員して捜索すべきです！","ENG":"Doctor, we must send all our soldiers to search for her!","TWN":"博士，要派出所有士兵進行搜查嗎！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"잠깐, 그냥 내버려두게.","JPN":"待て、放っておけ。","ENG":"Wait, just leave her be.","TWN":"等一下，先放著不管吧。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"뭐, 뭐라구요?","JPN":"な、なんて言いました？","ENG":"W-what?","TWN":"什，什麼？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"실험실에만 가둬놔도 유의미한 결과가 나올 거란 보장은 없지.","JPN":"実験室に閉じ込めておいても有意義な結果が出るという保証はない。","ENG":"There is no guarantee that we will get meaningful results locking her up in a lab.","TWN":"就算只關在實驗室裡，也不能保證會出現有意義的結果。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"어차피 그림자로 변이되는 것은 기정사실일세.","JPN":"どうせシャドウに変異することは既定事実だ。","ENG":"It's given that she'll turn into a Shadow.","TWN":"反正變成暗影是既定事實。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"우리의 연구가 어떤 결과를 맞이할지 직접 확인해 보지.","JPN":"我々の研究がどんな結果を向かえるのか、直接確認してみよう。","ENG":"Let's see for ourselves what outcomes our research will bring.","TWN":"就這麼看看我們的研究會變成什麼樣吧。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"하아… 하아…!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊…哈啊…！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마을이구나… 성공이야…!","JPN":"村だ……成功だね……！","ENG":"It's a village...! I made it...!","TWN":"是村子……成功了……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너무 추워… 배고파….","JPN":"寒すぎ……お腹空いた……","ENG":"I'm so cold... and hungry...","TWN":"好冷……好餓……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너무… 졸려….","JPN":"すごく……眠い……","ENG":"I'm so... tired...","TWN":"好……睏……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헉?! 여, 여긴…?","JPN":"はっ！？　こ、ここは……？","ENG":"Huh?! W-where am I...?","TWN":"嚇？！這，這裡是……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"깨어나서 다행이군. 조금만 더 늦었으면 죽었을 거다.","JPN":"目覚めてよかったな。少しでも遅かったら死んでいた。","ENG":"You're awake. If I was a little late, you'd already be dead.","TWN":"醒過來真是太好了。再晚一點你就死了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"히, 히익?!","JPN":"ひ、ひいっ！？","ENG":"E-eeek!","TWN":"呃咳？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"난 북방군이 아냐. 안심해라.","JPN":"私は北方軍ではない。安心しろ。","ENG":"I'm not with the Northern Army. Rest assured.","TWN":"我不是北方軍，放心吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"여긴 시린그라드 마을이다. 북방합의체의 별 볼일 없는 마을이지.","JPN":"ここはシリングラード。北方合意体の辺鄙な村だ。","ENG":"This is Ciringrad. A small village in the Northern Union.","TWN":"這裡是錫林格勒，北方和議會裡一個不起眼的村子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"난 보리스라고 한다. 그냥 독거하는 아저씨라 생각해라.","JPN":"私はボリスという。一人暮らしのただのおじさんだ。","ENG":"I'm Boris. Just think of me as a guy living on his own.","TWN":"我叫布里斯，就當我是個獨居的老頭吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"워치는 걱정하지 않아도 돼. 이터니움은 충분히 채워놨으니까.","JPN":"ウォッチのことは心配しなくていい。エタニウムは満たしておいた。","ENG":"Don't worry about your Watch. I've charged it with enough Eternium.","TWN":"不用擔心能量環，永恆之金已經補上了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"넌 이름이 뭐지?","JPN":"お前の名前は何だ？","ENG":"What’s your name?","TWN":"你叫什麼名字？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"……사샤에요.","JPN":"……サシャです。","ENG":"...Sasha.","TWN":"……我叫莎夏。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아, 아저씨. 정말 북방군 아닌 거 맞죠…?","JPN":"お、おじさん。本当に北方軍じゃないんですよね……？","ENG":"A-are you really not with the Northern Army...?","TWN":"大，大叔。你真的不是北方軍嗎…？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"구해주셔서 감사합니다….","JPN":"助けてくれてありがとうございます……","ENG":"Thank you for saving me...","TWN":"謝謝你救了我……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"경계심은 함부로 놓는거 아냐. 낯선 사람 앞에선 순진하게 굴지 마라.","JPN":"見知らぬ人の前ですぐに警戒心を解くもんじゃない。","ENG":"You shouldn't let your guard down so easily. And don't act so naive in front of strangers.","TWN":"不能隨便放下戒心，也不要在陌生人面前表現得太天真。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"하지만 아저씨… 절 구해주신 거 맞죠?","JPN":"でもおじさん……私を助けてくれたんですよね？","ENG":"But you... saved me, didn't you?","TWN":"可是大叔……你真的救了我，對吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"에헤헤… 아저씨도 낯선 절 구해줬잖아요.","JPN":"えへへ……おじさんも見知らぬ私を助けてくれたじゃないですか。","ENG":"Ehehe... You saved a stranger too, you know.","TWN":"嘿嘿……大叔你也救了我這個陌生人啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"……방금전까지 죽을뻔했던 녀석인게 맞나 싶군.","JPN":"……本当にさっきまで死にかけていたやつか？","ENG":"...Guess you weren't on the brink of death like I had assumed.","TWN":"……剛才還一副快要死掉的樣子，現在倒是很有精神嘛。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"목숨은 건졌고, 이젠 어쩔 생각이냐.","JPN":"命は助かったが、これからどうするつもりだ。","ENG":"You're still alive and well, so what are you going to do now?","TWN":"撿回了一條命，你之後打算怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그게….","JPN":"そ、それが……","ENG":"W-well...","TWN":"那，那個……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"생각해 본 적 없어요. 그냥, 살고 싶었어요.","JPN":"考えてないですよ。ただ、生きたかっただけです。","ENG":"I didn't think of anything. I just want to live.","TWN":"我從來沒想過。我只是想活下去。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"마침 일손이 부족했는데 잘됐군.","JPN":"人手不足だったから、ちょうどいい。","ENG":"Great. I'm a bit shorthanded right now.","TWN":"正好缺人手，來得正好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"당분간 여기서 지내게 해줄 테니까, 대신 내 일을 돕거라.","JPN":"しばらくここに泊めてやるから、その代わり私の仕事を手伝え。","ENG":"I'll let you stay here for the time being, but you'll have to help me with my work.","TWN":"我可以暫時讓你在這裡住下，但你要幫我做事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"싫다면 그냥 떠나도 상관없어. 선택은 네가 하는거다.","JPN":"嫌ならこのまま出ていっても構わない。自分で選択しろ。","ENG":"If you're not interested, you're free to leave. The decision is yours.","TWN":"如果不願意，隨時可以離開。選擇權在你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"도, 도울게요! 저, 전 물건을 고치는 능력이 있으니까, 분명 도움이 될 거예요!","JPN":"て、手伝います！　わ、私、物を修理する能力がありますから、きっと役に立ちますよ！","ENG":"I-I'll help! I have an ability to fix things, so I'm sure I'll be helpful!","TWN":"我，我會幫忙的！我有修理東西的能力，一定能幫上忙！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L27_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"대단한걸 시킬 생각 없다. 자립할 수 있을 때까지만 봐주는 거야.","JPN":"そんなたいそうな仕事は任せない。自立できるまで面倒を見てやるだけだ。","ENG":"I'm not thinking of making you do anything extraordinary. I'm just looking after you until you can become independent.","TWN":"不會讓你做什麼大事。只是照顧你到你能自立為止。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아, 아주머니. 안녕하세요!","JPN":"お、おばさん。こんにちは！","ENG":"H-hello, ma'am!","TWN":"阿，阿姨，你好！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"호, 혹시 빵 남은 것 있나요…?","JPN":"も、もしかして余ったパンはありますか……？","ENG":"A-are there any leftover bread...?","TWN":"那，那個……還有剩下的麵包嗎…？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"……저거 하나 가져가거라.","JPN":"……あれを一つ持って行きな。","ENG":"...Take one of those.","TWN":"……拿一個走吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"돈은 안 줘도 된다.","JPN":"お金は要らないよ。","ENG":"No need to give me money.","TWN":"不用給錢。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"엇, 정말요? 그래도 받으시지….","JPN":"えっ、本当ですか？　でも受け取った方が……","ENG":"Oh, really? But I insist...","TWN":"真，真的嗎？但我堅持……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저번에 보리스 아저씨한테 수리 맡기셨죠? 이번엔 제가 고쳐왔어요!","JPN":"この前、ボリスおじさんに修理を頼みましたよね？　今回は私が修理してきました！","ENG":"You requested a repair from Boris last time, right? I'm here to fix it this time!","TWN":"啊，對了！上次是把東西交給布里斯大叔修理了吧？這次是我修好的！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"어, 어때요?","JPN":"ど、どうですか？","ENG":"W-what do you think?","TWN":"怎，怎麼樣？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"거기 놓고 가.","JPN":"そこに置いていきな。","ENG":"Leave it there.","TWN":"放那就行。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"다음엔 보리스 양반이 직접 왔으면 좋겠구나.","JPN":"今度はボリスに直接来てほしいね。","ENG":"Have Boris come himself next time.","TWN":"下次讓布里斯那傢伙親自來吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네, 네? 혹시 안 고쳐졌나요?","JPN":"は、はい？　もしかして、直ってないですか？","ENG":"H-huh? Was it not fixed?","TWN":"嗯，啊？難道沒修好嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"그냥 그 양반한테 할 말이 있을 뿐이야.","JPN":"ただ、あの人に話があるだけだよ。","ENG":"I just need to have a word with him.","TWN":"只是有話要對那傢伙說而已。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네, 네… 안녕히 계세요.","JPN":"あっ、はい……それじゃあ。","ENG":"O-okay... Bye.","TWN":"嗯，嗯……再見。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤… 조금 말이 없으시긴 해도 나쁜 분은 아닌 것 같아.","JPN":"へへ……ちょっと無口だけど、悪い人じゃなさそう。","ENG":"Hehe... She's not that talkative, but I don't think she's a bad person.","TWN":"嘿嘿……雖然話不多，但感覺不是壞人。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이 빵은 이따 아저씨랑 같이 먹으면 되겠다.","JPN":"このパンは後でおじさんと一緒に食べよう。","ENG":"And I can share this bread with Boris.","TWN":"這麵包待會兒和大叔一起吃吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"빈틈이닷!","JPN":"隙あり！","ENG":"Gotcha!","TWN":"有破綻！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"꺅!","JPN":"きゃっ！","ENG":"Kyaaak!","TWN":"啊！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"에헷, 허점 투성이구만!","JPN":"えへっ、隙だらけだね！","ENG":"Heh, you're so easy to ambush!","TWN":"嘿嘿，破綻百出啊！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L4_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"아얏!","JPN":"いたっ！","ENG":"Ouch!","TWN":"哎呀！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"얘가 못하는 짓이 없어.","JPN":"まったく、すぐ調子に乗るんだから。","ENG":"Have you no boundaries?","TWN":"你這傢伙真是什麼都能幹得出來。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L9_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"엇, 부, 부단장님!","JPN":"あっ、ふ、副団長！","ENG":"Oh, D-Deputy!","TWN":"啊，副，副團長！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L10_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐가 부단장이야! 너 같은 말썽꾸러긴 절대 받아줄 생각 없으니까 집에나 가!","JPN":"何が副団長よ！　あなたのようなヤンチャは絶対受け入れないから、家に帰りなさい！","ENG":"Who are you calling Deputy?! I have no intention of taking in a troublemaker like you, so go home!","TWN":"什麼副團長！像你這樣的搗蛋鬼我絕對不會收的，回家去吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"에엑?! 아니 왜요!","JPN":"ええっ！？　そんな、何でですか！","ENG":"Eck?! Why not?!","TWN":"欸？？為什麼！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"가라고 했지!","JPN":"帰りなさいって言ったでしょ！","ENG":"I said, go!","TWN":"快走！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"큭… 두고봐요! 꼭 제가 필요할 때가 올 거라구요!","JPN":"くっ……見ててくださいよ！　私が必要な時が絶対来るはずですから！","ENG":"Kgh... Just you wait! You're going to need my help one day!","TWN":"哼……等著瞧吧！總有一天你會哭著求我的！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L15_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"하… 저 말썽꾸러기 녀석이…!","JPN":"はぁ……あのヤンチャ……！","ENG":"*Sigh* That troublemaker...!","TWN":"哀……這個搗蛋鬼……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"너, 못 보던 녀석인데. 이름이 뭐지?","JPN":"あなた、見ない顔ね。名前は？","ENG":"I haven't seen you around before. What's your name?","TWN":"是沒見過的生面孔，你叫什麼名字？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그… 사샤에요.","JPN":"えっと……サシャです。","ENG":"Uh... It's Sasha.","TWN":"那個……我叫莎夏。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이런 마을에서 잘도 지내고 있네.","JPN":"こんな村でよくもまあ暮らしてられるね。","ENG":"Seems like you adjusted well to a village like this one.","TWN":"在這種村子裡好像也過得不錯啊。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"엇… 죄송해요. 헤헤.","JPN":"あっ……すみません。へへ。","ENG":"Oh... I'm sorry. Hehe.","TWN":"啊……對不起，嘿嘿。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"웃자고 한 얘기 아냐.","JPN":"笑いごとじゃないよ。","ENG":"I didn't say that for laughs.","TWN":"不是開玩笑的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"난 올가. 시린그라드에서 민병단 일을 하고 있어.","JPN":"私はオルガ。シリングラードで民兵団の仕事をやってるの。","ENG":"I'm Olga. I work for the militia in Ciringrad.","TWN":"我是歐嘉，在錫林格勒做民兵的工作。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"침식체로부터 마을을 지키고 있지.","JPN":"侵食体から村を守ってるのよ。","ENG":"We protect the village from C.O.s.","TWN":"我們會保護村子免受侵蝕體的侵害。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저, 정말요…?","JPN":"ほ、本当ですか……？","ENG":"R-really...?","TWN":"真，真的嗎…？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼 저도 도울 일이 있을까요? 전 카운터에요!","JPN":"それじゃあ、私にも手伝うことがありますか？　私はカウンターです！","ENG":"Then, is there anything that I can do to help? I'm a Counter!","TWN":"那我也能幫上忙嗎？我是制裁者！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"카운터라… 꽤 쓸만하긴 하겠네.","JPN":"カウンターか……かなり役に立ちそうね。","ENG":"A Counter...? I think you'll be useful.","TWN":"制裁者啊……看起來還蠻有用的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그래도 어린애를 스카우트 할 생각은 없어.","JPN":"でも子どもをスカウトするつもりはないの。","ENG":"But I have no intention of recruiting a child.","TWN":"不過我沒打算招募小孩子。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그냥 못 보던 애가 보이길래 말 좀 걸어본 것뿐이야.","JPN":"ただ珍しい子がいたから話をかけてみただけ。","ENG":"I've never seen you before, so I just wanted to talk.","TWN":"只是看到一個陌生的孩子，隨便聊聊而已。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그래도 생각나면 꼭 찾아와주세요!","JPN":"で、でも、思いついたら絶対声をかけてくださいね！","ENG":"B-but please ask when you do need help!","TWN":"那，那如果你改變主意了，一定要來找我！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"알겠냐 사샤. 남한테 호의를 베풀어서 좋을 건 없어.","JPN":"いいか、サシャ？　他人に好意を示したところでいいことなんてない。","ENG":"Do you see, Sasha? Nothing good comes from doing favors for others.","TWN":"聽好了，莎夏，對別人施以恩惠是沒有好處的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그치만…!","JPN":"で、でも……！","ENG":"B-but...!","TWN":"可，可是…！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"내가 널 구해준 건, 그저 변덕일 뿐이었다.","JPN":"私がお前を助けたのは、ただの気まぐれだった。","ENG":"My saving you was just on a whim.","TWN":"我救你，只是臨時起意。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"고작 그걸로 대단한 인류애라도 느꼈던 거냐?","JPN":"たかがそんなことで崇高な人類愛でも感じたのか？","ENG":"Are you telling me you felt the warmth of humanity because of that?","TWN":"你以為這就是什麼了不起的人性溫暖嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤 맞아요. 너무 기뻤어요.","JPN":"へへ、そうですよ。とても嬉しかったんです。","ENG":"Hehe. Yes. I was so happy.","TWN":"嘿嘿，沒錯。我真的很開心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"나 원… 민병단은 위험한 일이다. 왜 굳이 힘든 일을 하려는 거냐?","JPN":"まったく……民兵団は危険な仕事だ。わざわざ、なぜ大変な仕事をしようとする？","ENG":"Ugh... The militia is dangerous. Why do you insist on doing hard labor?","TWN":"真是的……民兵的工作很危險，為什麼非要做這麼辛苦的事？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그야… 전 카운터잖아요?","JPN":"そりゃ……私はカウンターでしょう？","ENG":"Because... I'm a Counter?","TWN":"因為……我是制裁者啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"히힛… 전 사람들에게 도움이 되고 싶어요!","JPN":"へへっ……私は人の役に立ちたいんです！","ENG":"Hehe... I just want to be of help to people!","TWN":"嘿嘿……我想幫助別人！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"매번 뭐가 그리 좋다고 웃는 건지…","JPN":"毎度何がそんなに嬉しくて笑ってるのかわからないな……","ENG":"What are you always so giddy about...?","TWN":"每次都笑得那麼開心……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"이것 받아. 그 빵집 여자가 준 거다.","JPN":"ほら。あのパン屋の女がくれたものだ。","ENG":"Take this. It's from the bakery owner.","TWN":"接著，這是那個麵包店的女人給的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이게 뭐에요?","JPN":"これは何ですか？","ENG":"What is it?","TWN":"這是什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"피로조크라는 파이다. 이 마을에선 이만한 것도 없지.","JPN":"ピロシキというパイだ。この村では最高級の品だ。","ENG":"It's a pie called Pirozhki. There's nothing like it in this village.","TWN":"這是什麼餡餅的，在這個村子裡算是最好吃的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"그 불친절한 여자가 이런 것까지 주다니, 믿어지지 않는군.","JPN":"あの不親切な女がこんなものまでくれるなんて、信じられないな。","ENG":"I just can't believe that rude woman would give something like this to you.","TWN":"那個整天臭著臉的女人竟然會給你這個，真是難以置信。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"매일같이 찾아갔었지? 그 여자도 나름 정이란걸 아나보구만.","JPN":"毎日のように通ってただろう？　あの女も情ってものを知ってるようだ。","ENG":"You went to see her every day, right? Guess she's not as cold as she looks.","TWN":"你每天都有去找她吧？原來她也有感情。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마, 맛있다… 정말 맛있어요!","JPN":"お、美味しい……本当に美味しいです！","ENG":"I-it's so good...! I like it!","TWN":"好，好吃……真的很好吃！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"……다 먹어도 좋다.","JPN":"……全部食べていい。","ENG":"...You can have it all.","TWN":"……你可以全吃完沒關係。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Urgh!","TWN":"咳！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"괜찮나? 정신 차려야 한다!","JPN":"大丈夫か？　しっかりしろ！","ENG":"Are you okay? Be careful!","TWN":"沒事吧？打起精神來！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"미, 미안…!","JPN":"ご、ごめん……！","ENG":"S-sorry...!","TWN":"對，對不起……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"이번에도 키키모라는 나타나지 않았군.","JPN":"今回もキキーモラは現われなかったな。","ENG":"Kikimora didn't appear this time as well.","TWN":"這次奇奇莫拉也沒有出現啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그래도 2종들이 이렇게나 들이닥치면 골치 아픈데…","JPN":"だが、第2種がこれほど押し寄せてくると厄介だ……","ENG":"But having all these Category 2s is also a pain...","TWN":"不過這麼多2類侵蝕體湧過來，真是頭痛……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"음? 저건 뭐야?","JPN":"うむ？　あれは何だ？","ENG":"Hmm? What's that?","TWN":"嗯？那是什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아저씨들! 도우러 왔어요!","JPN":"おじさんたち！　助けに来ました！","ENG":"Guys! I'm here to help!","TWN":"大家！我來幫忙了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"사, 사샤?! 여긴 놀이터가 아니야!","JPN":"サ、サシャ！？　ここは遊び場じゃないの！","ENG":"S-Sasha?! This isn't a playground!","TWN":"莎，莎夏？！這裡可不是遊樂場！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그 정돈 저도 안다구요!","JPN":"そんなことは私もわかってます！","ENG":"I know that much!","TWN":"這些我也知道啊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"보리스 아저씨가 엄청 세 보이는 무기들 잔뜩 가지고 있던데, 제가 전부 고쳐왔어요!","JPN":"ボリスおじさんがめちゃくちゃ強そうな武器をいっぱい持っていたので、私が全部修理してきました！","ENG":"Boris had a bunch of powerful-looking weapons, and I fixed them all!","TWN":"布里斯大叔有好多看起來很厲害的武器，我全都修好了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"올가. 저 아이가 설마 저번에 말했던 카운터냐?","JPN":"オルガ。まさかあの子がこの前話したカウンターなのか？","ENG":"Olga, is she the Counter you mentioned before?","TWN":"歐嘉，那孩子不會就是上次說的制裁者吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"하… 저렇게 대책 없는 녀석일 줄은 몰랐어.","JPN":"はあ……あんなに無鉄砲なやつだなんて知らなかったよ。","ENG":"*Sigh* Didn't think she'd be this reckless.","TWN":"哀……沒想到她也這麼粗線條。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐, 뭐 하는 거야?! 이 자식들아!","JPN":"な、何してるの！？　あんたたち！","ENG":"W-what are you doing?! You idiots!","TWN":"你在做什麼啊？！你這個傻瓜！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"이거라도 써봐야지! 우리가 가진 총만으론 역부족이었다고!","JPN":"これでも使ってみるか！　俺たちの銃だけじゃ力不足だったんだ！","ENG":"We have to at least try them out! It's not enough with just our current weapons!","TWN":"要不還是試試吧！光靠我們的槍不夠用！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"휴~ 침식체들은 더 이상 안 보이네요. 다행이다…!","JPN":"ふう～もう侵食体は見えませんね。よかった……！","ENG":"Phew! I don't think I see any more C.O.s now. What a relief...!","TWN":"呼～侵蝕體沒了。太好了……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아얏!","JPN":"いたっ！","ENG":"Ouch!","TWN":"啊呀！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L38_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"멍청한 것도 정도가 있잖아!","JPN":"考えなしにも程がある！","ENG":"How stupid are you?!","TWN":"犯蠢也要有限度！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"다음부턴 절대 나서지 마 알았어?","JPN":"次からは絶対こんなことしないでね、わかった？","ENG":"Don't ever do that again, got that?","TWN":"下次絕對不要來了，知道嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네, 네… 언니.","JPN":"は、はい……オルガさん。","ENG":"O-okay, Ms. Olga.","TWN":"是，是……姊姊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"언니라고…?","JPN":"オルガさん……？","ENG":"Ms. Olga...?","TWN":"姊姊……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"뭐 어때, 이 녀석 덕분에 침식체들을 처리할 수 있었잖아.","JPN":"まあ、いいじゃないか。こいつのおかげで侵食体をやっつけられたし。","ENG":"Who cares? We were able to fend off the C.O.s thanks to her.","TWN":"讓她來嘛，這傢伙幫我們處理了侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"침식체한테도 겁먹지 않는 앤 처음 봤어. 크게 되겠는걸?","JPN":"侵食体を怖がらない子どもは初めて見た。偉いな。","ENG":"I've never seen a kid who wasn't afraid of C.O.s. I see a bright future in front of you.","TWN":"第一次見到不怕侵蝕體的人，前途無量啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"에, 에헤헤… 정말요?","JPN":"え、えへへ……本当ですか？","ENG":"E-ehehe... You really think so?","TWN":"欸，欸嘿嘿……真的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"네가 올가가 말했던 카운터로군. 아까는 정말 큰 도움이 됐다.","JPN":"お前がオルガが話していたあのカウンターか。さっきは本当に助かった。","ENG":"So you're the Counter Olga talked about. I appreciate your helping us out.","TWN":"你就是歐嘉提到的制裁者啊。剛才真是幫了大忙。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"하지만 카운터라곤 해도 너무 무모했어.","JPN":"だが、いくらカウンターとはいえ、あまりにも無謀すぎたぞ。","ENG":"But even if you are a Counter, that was too reckless.","TWN":"不過，就算是制裁者，也太莽撞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"죄송해요….","JPN":"すみません……","ENG":"I'm sorry...","TWN":"對不起……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"……후방 지원 정도라면 괜찮겠지.","JPN":"……後方支援くらいなら大丈夫だろう。","ENG":"...But I think it'll be okay for you to assist with rear support.","TWN":"嗯……後方支援的話，應該沒問題。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저, 정말요?","JPN":"ほ、本当ですか？","ENG":"R-really?","TWN":"真，真的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>안드레이! 당신 지금 무슨 말을 하는 거야?!</color>","JPN":"<color=#ffd34c>アンドレイ！　あなた今何を言ってるの！？</color>","ENG":"<color=#ffd34c>Andrei! You can't be serious!</color>","TWN":"<color=#ffd34c>安德烈！你在說什麼？！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"상관없잖아. 우린 한 명이라도 더 많은 전력이 필요해.","JPN":"いいではないか。俺たちには一人でも多くの戦力が必要だ。","ENG":"That shouldn't concern you. Plus, we need all the help we can get.","TWN":"沒關係，我們需要更多的戰力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"이 아인 카운터니까, 경험을 쌓으면 유능한 대원이 될 거야.","JPN":"この子はカウンターだから、経験を積めば有能な隊員になるだろう。","ENG":"She's a Counter. And with experience, she'll become a capable member.","TWN":"這孩子是制裁者，經驗多了就會成為優秀的隊員。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼… 앞으로도 잘 부탁드릴게요 언니. 에헤헤.","JPN":"では……これからよろしくお願いします、オルガさん。えへへ。","ENG":"Then... I look forward to continuing our work with you, Ms. Olga. Ehehe.","TWN":"那麼……以後也請多多關照，姊姊，欸嘿嘿。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L16_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"하… 정말이지….","JPN":"はあ……まったく……","ENG":"*Sigh* This can't be happening...","TWN":"哀……真是的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"많이 노력했던 덕분일까? 마을 사람들은 점점 나에게 따뜻하게 대해줬어.","JPN":"一生懸命頑張ったからなのか、村の人たちは徐々に優しく接してくれるようになった。","ENG":"Was it because of all my hard work? But the village people started to open up to me.","TWN":"是因為我的努力嗎？村裡的人們漸漸對我熱情了起來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"처음엔 적응하기 조금 힘들었지만… 이젠 고향과도 같은 곳이 되었지.","JPN":"最初は適応するのに苦労したけど……今では故郷のような場所になっていた。","ENG":"It was hard to adjust to it at first... but now, this place was like home.","TWN":"剛開始有點難以適應……但現在已經像是家一樣的地方了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"카운터 능력을 얻게 된 건 저주라고만 생각했는데….","JPN":"カウンターの能力はただの呪いでしかないと思っていたのに……","ENG":"I always thought becoming a Counter was a curse...","TWN":"曾經以為獲得制裁者的能力是種詛咒……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"이젠 꼭 그렇지만은 않다고 생각하게 되었어.","JPN":"今はもうそうでもないって思えるようになったよ。","ENG":"But now, I don't think that's the case.","TWN":"但我現在不再這麼想了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"더 이상 아프지 않고, 배고프지도 않아.","JPN":"もう痛くないし、お腹もすいてない。","ENG":"I'm not in pain, or hungry anymore.","TWN":"不再感到痛苦，也不再饑餓。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"하지만… 가끔씩 연구소에 있었던 일이 꿈에서 나오곤 해.","JPN":"でも……たまに研究所でのできごとが夢に出てきたりする。","ENG":"But... I sometimes get nightmares of when I was at the research lab.","TWN":"但是……有時候在夢裡會出現研究所的影子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"나 말고도 <color=#ffd34c>실험체로 사용된 아이…</color>","JPN":"私以外にも<color=#ffd34c>実験体として使われた子</color>……","ENG":"<color=#ffd34c>The other girl who got used as a test subject...</color>","TWN":"除了我，還有其他<color=#ffd34c>被當作實驗品的孩子</color>……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"내가 도망쳤기 때문에… 나 대신 인형에 들어가게 된 아이….","JPN":"私が逃げたせいで……私の代わりに人形に入ることになった子……","ENG":"The one who became a Doll... because I ran away...","TWN":"因為我逃跑了……所以那個孩子代替我被放進了娃娃裡……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그 아이까진 구할 순 없었어….","JPN":"あの子までは助けることができなかった……","ENG":"I couldn't save her...","TWN":"我救不了她……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"끄악! 내 얼굴!!","JPN":"って、わあっ！　顔に！！","ENG":"Gwah! My face!!","TWN":"啊啊啊！我的臉！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아파라… 어? 이건….","JPN":"イタタ……えっ？　これは……","ENG":"Oww... Huh? Is this… a person?","TWN":"好痛……咦？這是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"사람? 아니야. 이 아이는 분명….","JPN":"人…？　違う、この子は確か……","ENG":"No. This child is–","TWN":"人？不對。這個孩子明明是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그 아이가 분명해…!</color>","JPN":"<color=#ffd34c>きっとあの子だよ……！</color>","ENG":"<color=#ffd34c>It's her...!</color>","TWN":"<color=#ffd34c>一定是那個孩子……！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>좋아… 한번 해보는 거야…!</color>","JPN":"<color=#ffd34c>よし……やってみようじゃない……！</color>","ENG":"<color=#ffd34c>Okay... Let's do this...!</color>","TWN":"<color=#ffd34c>好……那就試試看……！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"처음엔 그저 죄책감이었어. 호의도 뭐도 아닌 그저 죄책감…","JPN":"最初はただの罪悪感だった。好意でもなんでもない、ただの罪悪感……","ENG":"It was guilt at first. Not kindness or anything, but guilt...","TWN":"一開始只是內疚。無關善良什麼的，只是內疚……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"하지만… 더 이상 마브카는 나의 죄책감이 아냐….","JPN":"でも……もうマブカは私の罪悪感じゃない……","ENG":"But... Mavka isn't my guilt anymore...","TWN":"但是後來……瑪卡就不再是我的內疚了……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"마브카. 넌 나의 둘도 없는 친구.","JPN":"マブカ。あなたは私の大切な友だち。","ENG":"Mavka, you're my best friend.","TWN":"瑪卡，你是我無可替代的朋友。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>내 목숨과도 맞바꿀….</color>","JPN":"<color=#ffd34c>私の命とも引き換えられる……</color>","ENG":"<color=#ffd34c>Someone I'd trade my life for...</color>","TWN":"<color=#ffd34c>可以用我的生命來交換……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"있잖아 마브카. 사실… 다 말해주고 싶었어.","JPN":"ねえ、マブカ。本当はね……全部話してあげたかったの。","ENG":"You know, Mavka. I actually... wanted to tell you everything.","TWN":"你知道嗎，瑪卡，其實……我一直想告訴你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"나도 너처럼 북방군의 실험체였고… 머지않아 그림자로 변이될 거라는 것도….","JPN":"私もあなたみたいに北方軍の実験体で……もうすぐシャドウに変異するってことも……","ENG":"That I was also a test subject for the Northern Army... and that I'll soon become a Shadow...","TWN":"我也像你一樣是北方軍的實驗品……而且不久之後，我就會變成暗影了……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"고물 더미에서 널 처음 발견했을 때, 사실 한눈에 알아봤었어.","JPN":"古鉄の山であなたを初めて見つけた時、実は一目でわかったよ。","ENG":"When I found you in the junk pile, I knew at first sight.","TWN":"當我第一次在垃圾堆裡發現你的時候，其實一眼就認出來了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"마브카는 나한테 모든 사연을 말해줬는데… 난 끝까지 숨기기만 했어.","JPN":"マブカは私にすべて話してくれたのに……私は最後まで隠してばかりいた。","ENG":"You've told me everything about yourself, but... I kept hiding mine from you.","TWN":"瑪卡把自己所有的故事都告訴了我……但我一直在隱瞞。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"너무 무서웠어… 거짓말 한 날 원망할까 봐….","JPN":"とても怖かったの……ウソついた私のことを恨むと思って……","ENG":"I was so afraid... that you'd resent me for lying to you...","TWN":"我真的很害怕……怕你會怪我撒謊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"마브카가… 내 곁을 떠날까 봐….","JPN":"マブカが……私のそばから離れていくかもしれないから……","ENG":"That you, Mavka... would leave me...","TWN":"怕瑪卡……會離開我……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"아픈게 다 나으면, 전부 말해줄 거야.","JPN":"治ったら、全部話してあげるよ。","ENG":"Once I'm all better, I'm going to tell you everything.","TWN":"等病好了，我會把一切都告訴你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"그리고… 꼭 사과할게.","JPN":"そして……必ず謝るね。","ENG":"And... I'll apologize to you.","TWN":"然後……一定跟你道歉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"미안하다는 말… 이것만큼은 꼭 전해주고 싶어….","JPN":"ごめんって言葉……これだけは必ず伝えたい……","ENG":"Among everything I want to say to you... I want to tell you that I'm sorry...","TWN":"對不起……這句話我一定要告訴你……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"정말 미안해….","JPN":"本当にごめんね……","ENG":"I really am...","TWN":"真的對不起……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"정말….","JPN":"本当に……","ENG":"Really...","TWN":"真的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"미안해… 마브카….","JPN":"ごめん……マブカ……","ENG":"I'm sorry... Mavka...","TWN":"對不起……瑪卡……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"}]`);export{e as default};